import React, {
  Dispatch,
  SetStateAction,
  useCallback,
  useEffect,
  useMemo,
  useState,
  memo
} from 'react'
import { useDispatch, useSelector } from 'react-redux'
import { MachineParams, MachineReply } from 'api/model/property/parking/machineModel'
import { create, find, update } from 'modules/property/parking/machine'
import {
  Box,
  CircularProgress,
  FormLabel,
  Stack,
  Button,
  TextField,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  MenuItem
} from '@mui/material'
import message from 'components/Message'
import { buttonStyles } from 'components/DeleteModal'

interface FormDialogProps {
  dialogValue?: MachineReply
  openDialog: boolean
  dialogType: string
  setOpenDialog: Dispatch<SetStateAction<boolean>>
}

const FormDialog: React.FC<FormDialogProps> = ({
  dialogValue,
  openDialog,
  dialogType,
  setOpenDialog
}) => {
  const dispatch = useDispatch<AppDispatch>()
  const { page } = useSelector((state: RootState) => state.MachineSlice)
  const { list } = useSelector((state: RootState) => state.ParkingAreaSlice)
  const [loading, setLoading] = useState(false)

  const initialFormData = useMemo(
    () => ({
      machineCode: dialogType === 'edit' ? dialogValue?.machineCode || '' : '',
      machineName: dialogType === 'edit' ? dialogValue?.machineName || '' : '',
      machineIp: dialogType === 'edit' ? dialogValue?.machineIp || '' : '',
      direction: dialogType === 'edit' ? dialogValue?.direction || '' : ''
    }),
    [dialogType, dialogValue]
  )
  const [formData, setFormData] = useState<MachineParams>(initialFormData)

  useEffect(() => {
    setFormData(initialFormData)
  }, [initialFormData])

  const handleSubmit = useCallback(
    async (event: React.FormEvent<HTMLFormElement>) => {
      event.preventDefault()
      setLoading(true)
      try {
        const current_community = localStorage.getItem('current_community')
        const community = JSON.parse(current_community || '')
        const params = { ...formData, communityId: community?.id }
        const action =
          dialogType === 'add' ? create(params) : update({ id: dialogValue?.id, ...params })
        const res = await dispatch(action)
        if ('error' in res && res.error?.message) {
          throw new Error(res.error.message)
        }
        await dispatch(find({ 'page.num': page.num || '1', 'page.size': page.size }))
        message.success(dialogType === 'add' ? '新建成功' : '编辑成功')
        setOpenDialog(false)
        setFormData(initialFormData)
      } catch (err: unknown) {
        setLoading(false)
        if (err instanceof Error) message.error(err.message)
      } finally {
        setLoading(false)
      }
    },
    [dispatch, dialogType, dialogValue, formData, page, setOpenDialog, initialFormData]
  )

  return (
    <Dialog
      fullWidth
      maxWidth="sm"
      open={openDialog}
      onClose={() => setOpenDialog(false)}
      slotProps={{ paper: { component: 'form', onSubmit: handleSubmit } }}
    >
      <DialogTitle>{dialogType === 'add' ? '新增' : '编辑'}</DialogTitle>
      <DialogContent dividers sx={{ margin: '0 10px 0' }}>
        <Stack spacing={3}>
          <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <FormLabel>设备名称：</FormLabel>
            <TextField
              placeholder="必填，请填写设备名称"
              sx={{ width: '80%' }}
              type="text"
              size="small"
              value={formData.machineName}
              onChange={e => setFormData({ ...formData, machineName: e.target.value })}
              variant="outlined"
            />
          </Box>
          <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <FormLabel>设备编码：</FormLabel>
            <TextField
              placeholder="必填，请填写设备编码"
              sx={{ width: '80%' }}
              type="text"
              size="small"
              value={formData.machineCode}
              onChange={e => setFormData({ ...formData, machineCode: e.target.value })}
              variant="outlined"
            />
          </Box>
          <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <FormLabel>设备IP：</FormLabel>
            <TextField
              placeholder="必填，请填写设备IP"
              sx={{ width: '80%' }}
              type="text"
              size="small"
              value={formData.machineIp}
              onChange={e => setFormData({ ...formData, machineIp: e.target.value })}
              variant="outlined"
            />
          </Box>
          <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <FormLabel>设备方向：</FormLabel>
            <TextField
              label="请选择设备方向"
              sx={{ width: '80%' }}
              select
              size="small"
              value={formData.direction || ''}
              onChange={e => setFormData({ ...formData, direction: e.target.value })}
              variant="outlined"
            >
              {[
                { value: '3306', label: '进' },
                { value: '3307', label: '出' }
              ].map(option => (
                <MenuItem key={option.value} value={option.value}>
                  {option.label}
                </MenuItem>
              ))}
            </TextField>
          </Box>
          <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <FormLabel>道闸厂家：</FormLabel>
            <TextField
              label="请选择道闸厂家"
              sx={{ width: '80%' }}
              select
              size="small"
              value={formData.direction || ''}
              onChange={e => setFormData({ ...formData, direction: e.target.value })}
              variant="outlined"
            >
              {list.map(option => (
                <MenuItem key={option.id} value={option.id}>
                  {option.name}
                </MenuItem>
              ))}
            </TextField>
          </Box>
          <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <FormLabel>岗亭：</FormLabel>
            <TextField
              label="请选择岗亭"
              sx={{ width: '80%' }}
              select
              size="small"
              value={formData.direction || ''}
              onChange={e => setFormData({ ...formData, direction: e.target.value })}
              variant="outlined"
            >
              {list.map(option => (
                <MenuItem key={option.id} value={option.id}>
                  {option.name}
                </MenuItem>
              ))}
            </TextField>
          </Box>
          <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <FormLabel>监控视频：</FormLabel>
            <TextField
              label="请选择监控视频"
              sx={{ width: '80%' }}
              select
              size="small"
              value={formData.direction || ''}
              onChange={e => setFormData({ ...formData, direction: e.target.value })}
              variant="outlined"
            >
              {list.map(option => (
                <MenuItem key={option.id} value={option.id}>
                  {option.name}
                </MenuItem>
              ))}
            </TextField>
          </Box>
        </Stack>
      </DialogContent>
      <DialogActions>
        <Button variant="contained" color="error" onClick={() => setOpenDialog(false)}>
          取消
        </Button>
        <Button
          variant="contained"
          type="submit"
          color="error"
          sx={buttonStyles('#2660ad', '#1d428a')}
          disabled={loading}
          startIcon={loading && <CircularProgress size={24} color="inherit" />}
        >
          {loading ? '保存中...' : '保存'}
        </Button>
      </DialogActions>
    </Dialog>
  )
}

export default memo(FormDialog)
